49→    withProgress {
50→        val changes = undoableOp {
51→            if (!redoAvailable()) {
52→                OpChangesAfterUndo.getDefaultInstance()
53→            } else {
54→                redo()
55→            }
56→        }
57→        val message = if (changes.operation.isEmpty()) {
58→            TR.actionsNothingToRedo()
59→        } else {
60→            TR.undoActionRedone(changes.operation)
61→        }
62→        showSnackbar(message, duration)
63→    }
64→}
